const item = $node["Get row(s) in sheet2"].json;
const rawAddress = item["Адрес"] || item["адрес"] || "Ірпінь, Теліги 28"; 

// Чистим адрес и отделяем город для интерфейса
const addressParts = rawAddress.split(',');
const detectedCity = addressParts[0].trim(); // Берем первое слово до запятой

let googleAddress = rawAddress.trim();
if (!googleAddress.toLowerCase().includes("україна") && !googleAddress.toLowerCase().includes("украина")) {
    googleAddress += ", Україна";
}

return [{
  json: {
    address_for_google: googleAddress, 
    інтерфейс: {
        заголовок: "Розрахунок доставки VerbaDom",
        місто: detectedCity, // Теперь здесь будет "Ірпінь" или то, что ввел клиент
        статус: "Дані отримано"
    }
  }
}];

// 1. ПОЛУЧАЕМ ДАННЫЕ ИЗ ТЕКУЩЕГО МАРШРУТА
// Берем дистанцию напрямую из узла "Маршрут Киев"
const distanceKm = Math.round($node["Маршрут Киев"].json["distanceValue"] / 1000);

let finalCost = 0;
let statusMessage = "Дані отримано";

// 2. РАСЧЕТ СТОИМОСТИ (Логика VerbaDom)
if (distanceKm === 0) {
  finalCost = 350;
  statusMessage = "Зустріч на маршруті (Траса)";
} else if (distanceKm <= 15) {
  finalCost = 900;
} else if (distanceKm > 15 && distanceKm <= 20) {
  finalCost = 1100;
} else if (distanceKm > 20 && distanceKm <= 40) {
  finalCost = 1100 + ((distanceKm - 20) * 35);
} else {
  finalCost = 3000;
  statusMessage = "Потребує індивідуального узгодження";
}

// 3. ОКРУГЛЕНИЕ ДО ДЕСЯТКОВ
const roundedCost = Math.ceil(finalCost / 10) * 10;

// 4. ПЕРЕДАЕМ ДАННЫЕ ДАЛЬШЕ
// Мы УДАЛИЛИ привязку к Жмеринке. 
// Теперь код просто передает расчеты, а город "Ирпень" 
// будет браться из настроек вашего последнего узла Google Maps2.
return [{
  json: {
    finalCost: roundedCost,
    distanceKm: distanceKm,
    status: statusMessage
  }
}];
